33	const FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER = 0.85;
34	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
35	const LOYALTY_DISCOUNT_MIN_YEARS = 2;
36	const HIGH_ENCHANTMENT_THRESHOLD = 5;
37	const FOLLOW_UP_CONTRACT_MIN_COUNT = 1;
38	
39	interface Policy {
40	  basePremium: number;
41	  premium: number;
42	  items: Item[];
43	  insuranceSum: number;
44	  remainingCap: number;
45	}
46	
47	const roundToCents = (amount: number): number => Math.round(amount * 100) / 100;
48	
49	const multiplierIfEligible = (value: number, threshold: number, multiplier: number): number =>
50	  value >= threshold ? multiplier : 1;
51	
52	const PROCESSING_FEE = 5;
53	
54	const calculateItemCosts = (items: Item[]): number => {
55	  const nonCursedCountsByType: Record<string, number> = {};
56	  let cursedCost = 0;
57	  let enchantmentSurcharge = 0;
58	
59	  for (const item of items) {
60	    const itemBasePremium = BASE_PREMIUMS[item.type];
61	    if (item.cursed) {
62	      cursedCost += itemBasePremium * CURSED_SURCHARGE_MULTIPLIER;
63	    } else {
64	      nonCursedCountsByType[item.type] = (nonCursedCountsByType[item.type] ?? 0) + 1;
65	      if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
66	        enchantmentSurcharge += itemBasePremium * ENCHANTMENT_SURCHARGE_MULTIPLIER;
67	      }
68	    }
69	  }
70	
71	  let nonCursedCost = 0;
72	  for (const [type, count] of Object.entries(nonCursedCountsByType)) {
73	    if (count === 3) {
74	      nonCursedCost += BLOCK_PRICE_FOR_3_ALIKE;
75	    } else {
76	      nonCursedCost += count * BASE_PREMIUMS[type];
77	    }
78	  }
79	
80	  return cursedCost + nonCursedCost + enchantmentSurcharge;
81	};
82	
83	export function generateQuote(items: Item[], customer: Customer): Policy {
84	  const followUpMultiplier = multiplierIfEligible(customer.contractCount, FOLLOW_UP_CONTRACT_MIN_COUNT, FOLLOW_UP_CONTRACT_DISCOUNT_MULTIPLIER);
85	  const loyaltyMultiplier = multiplierIfEligible(customer.yearsWithMHPCO, LOYALTY_DISCOUNT_MIN_YEARS, LOYALTY_DISCOUNT_MULTIPLIER);
86	  const basePremium = roundToCents(calculateItemCosts(items) * FIRST_INSURANCE_SURCHARGE_MULTIPLIER * followUpMultiplier * loyaltyMultiplier);
87	  const insuranceSum = items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
88	  const remainingCap = 2 * insuranceSum;
89	  return { basePremium, premium: Math.ceil(basePremium + PROCESSING_FEE), items, insuranceSum, remainingCap };
90	}
91	
92	const DEDUCTIBLE = 100;
93	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
94	const HIGH_ENCHANTMENT_PAYOUT_MULTIPLIER = 0.5;
95	
96	interface Damage {
97	  itemType: string;
98	  amount: number;
99	}
100	
101	interface Incident {
102	  cause: string;
103	  damages: Damage[];
104	}
105	
106	const applyEnchantmentReduction = (amount: number, enchantment: number): number =>
107	  enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
108	    ? amount * HIGH_ENCHANTMENT_PAYOUT_MULTIPLIER
109	    : amount;
110	
111	export function processClaim(policy: Policy, incident: Incident): { payout: number; remainingCap: number } {
112	  const damage = incident.damages[0];
113	  const item = policy.items.find((i) => i.type === damage.itemType);
114	  const enchantment = item?.enchantment ?? 0;
115	  const effectiveDamage = applyEnchantmentReduction(damage.amount, enchantment);
116	  const payoutBeforeCap = Math.max(0, effectiveDamage - DEDUCTIBLE);
117	  const payout = Math.floor(Math.min(payoutBeforeCap, policy.remainingCap));
118	  return { payout, remainingCap: policy.remainingCap - payout };
119	}
